-- Cleanup for temporary dispute_messages RLS QA rows.

DELETE FROM public.dispute_messages
WHERE order_id IN (
  '30000000-0000-4000-8000-000000000301',
  '30000000-0000-4000-8000-000000000302',
  '30000000-0000-4000-8000-000000000303'
);

DELETE FROM public.disputes
WHERE order_id IN (
  '30000000-0000-4000-8000-000000000301',
  '30000000-0000-4000-8000-000000000302',
  '30000000-0000-4000-8000-000000000303'
);

DELETE FROM public.orders
WHERE id IN (
  '30000000-0000-4000-8000-000000000301',
  '30000000-0000-4000-8000-000000000302',
  '30000000-0000-4000-8000-000000000303'
);

DELETE FROM public.listings
WHERE id = '20000000-0000-4000-8000-000000000201';

DELETE FROM public.profiles
WHERE id IN (
  '10000000-0000-4000-8000-000000000101',
  '10000000-0000-4000-8000-000000000102',
  '10000000-0000-4000-8000-000000000103',
  '10000000-0000-4000-8000-000000000104'
);

DELETE FROM auth.users
WHERE id IN (
  '10000000-0000-4000-8000-000000000101',
  '10000000-0000-4000-8000-000000000102',
  '10000000-0000-4000-8000-000000000103',
  '10000000-0000-4000-8000-000000000104'
);

SELECT 'qa_cleanup_complete' AS result;
